import { useBlockProps, RichText } from '@wordpress/block-editor';
import { colourVar, fontSizeVar } from '../../utils';

/**
 * Format a number with thousand separators.
 *
 * @param {number}  num       The number to format.
 * @param {boolean} separator Whether to add thousand separators.
 * @return {string} Formatted number string.
 */
function formatNumber( num, separator ) {
	if ( separator ) {
		return num.toLocaleString( 'en-GB' );
	}
	return String( num );
}

export default function Save( { attributes } ) {
	const {
		number,
		prefix,
		suffix,
		label,
		duration,
		separator,
		numberColour,
		labelColour,
		labelFontSize,
		icon,
		accentStroke,
	} = attributes;

	const className = [
		'sgs-counter',
		accentStroke ? 'sgs-counter--accent-stroke' : '',
	].filter( Boolean ).join( ' ' );

	const blockProps = useBlockProps.save( { className } );

	const numberStyle = {
		color: colourVar( numberColour ) || undefined,
	};

	const labelStyle = {
		color: colourVar( labelColour ) || undefined,
		fontSize: fontSizeVar( labelFontSize ) || undefined,
	};

	const formattedNumber = formatNumber( number, separator );
	const fullText = `${ prefix || '' }${ formattedNumber }${ suffix || '' } ${ label }`;

	return (
		<div { ...blockProps }>
			{ /* Icon slot — rendered server-side via render.php for Lucide SVG output.
			     The icon attribute is saved here as a data attribute so render.php can read it. */ }
			{ icon && (
				<span
					className="sgs-counter__icon-placeholder"
					data-icon={ icon }
					aria-hidden="true"
				/>
			) }
			<span className="sgs-sr-only">{ fullText }</span>
			<span
				className="sgs-counter__number"
				style={ numberStyle }
				data-target={ number }
				data-duration={ duration }
				data-separator={ separator ? 'true' : 'false' }
				data-prefix={ prefix || undefined }
				data-suffix={ suffix || undefined }
				aria-hidden="true"
			>
				{ prefix }
				{ formattedNumber }
				{ suffix }
			</span>
			<RichText.Content
				tagName="p"
				className="sgs-counter__label"
				value={ label }
				style={ labelStyle }
				aria-hidden="true"
			/>
		</div>
	);
}
